import React, { useState } from 'react';
import { ChevronLeft, AlertTriangle, ArrowDownCircle } from 'lucide-react';

export default function WithdrawGoalScreen({ goal, onBack, onConfirm }) {
  const [amount, setAmount] = useState('');
  const activeGoal = goal || { title: 'New Car', current: 8000 };

  const handleConfirm = () => {
    if (!amount || Number(amount) <= 0 || Number(amount) > activeGoal.current) return;
    onConfirm(Number(amount));
  };

  return (
    <div className="flex flex-col h-full bg-white animate-in fade-in duration-300">
      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900">Withdraw from Goal</h1>
      </div>

      <div className="p-6 flex-1">
        <div className="bg-red-50 border border-red-100 p-8 rounded-[2.8rem] text-center mb-10">
          <p className="text-red-400 text-[10px] font-black uppercase tracking-widest mb-1">Available in {activeGoal.title}</p>
          <h2 className="text-4xl font-black text-red-600">${activeGoal.current.toLocaleString()}</h2>
        </div>

        <div className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Amount to move</label>
            <input 
              type="number" 
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              placeholder="0.00" 
              className="w-full p-5 rounded-3xl bg-gray-50 border border-gray-100 outline-none focus:border-red-500 text-3xl font-black text-center"
            />
          </div>

          <div className="flex gap-4 p-5 bg-orange-50 rounded-[2rem] border border-orange-100">
            <AlertTriangle className="text-orange-500 shrink-0" size={24} />
            <p className="text-xs text-orange-700 font-bold leading-relaxed">
              Caution: Withdrawing before reaching your target might delay your goal achievement date.
            </p>
          </div>
        </div>
      </div>

      <div className="pb-64">
        <button 
          onClick={handleConfirm}
          className="w-full py-4 rounded-2xl font-black text-white bg-gray-900 shadow-xl flex items-center justify-center gap-3 active:scale-[0.98] transition-all"
        >
          <ArrowDownCircle size={20} />
          Move to Main Balance
        </button>
      </div>
    </div>
  );
}
